@Configuration
@EnableWebSecurity
class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http, SAMLAuthenticationFilter samlAuthenticationFilter) throws Exception {
        http
            .csrf().disable()
            .authorizeRequests()
                .antMatchers("/saml/**").permitAll()
                .anyRequest().authenticated()
            .and()
            .addFilterBefore(samlAuthenticationFilter, UsernamePasswordAuthenticationFilter.class);
        return http.build();
    }
}

@Component
class SAMLAuthenticationFilter extends OncePerRequestFilter {

    private final SAMLService samlService;

    public SAMLAuthenticationFilter(SAMLService samlService) {
        this.samlService = samlService;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) 
            throws ServletException, IOException {
        
        if (request.getRequestURI().equals("/saml/acs") && "POST".equals(request.getMethod())) {
            try {
                String samlResponse = request.getParameter("SAMLResponse");
                if (samlResponse == null || samlResponse.trim().isEmpty()) {
                    response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing SAMLResponse");
                    return;
                }
                
                SAMLUserDetails userDetails = samlService.processSAMLResponse(samlResponse);
                SAMLAuthentication authentication = new SAMLAuthentication(userDetails);
                SecurityContextHolder.getContext().setAuthentication(authentication);
                
                HttpSession session = request.getSession(true);
                session.setAttribute("SPRING_SECURITY_CONTEXT", SecurityContextHolder.getContext());
                session.setMaxInactiveInterval(3600);
                
                response.sendRedirect("/dashboard");
                return;
            } catch (Exception e) {
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Authentication failed");
                return;
            }
        }
        
        filterChain.doFilter(request, response);
    }
}

